SELECT average_rating
FROM top_ten_list
WHERE variety_id = 1;

SELECT AVG(stars) AS Average_Rating
FROM noodle_reviews
WHERE variety_id = 1;

SELECT review_id, stars
FROM noodle_reviews
WHERE verified_purchase = 'Yes';

SELECT *
FROM noodle_reviews
WHERE price = (SELECT MAX(price) FROM noodle_reviews);
